// Validating port mappings
function validatePortMappings(portMappings) {
	if (!Array.isArray(portMappings)) {
		return false;
	}
	for (let i = 0; i < portMappings.length; i++) {
		const portMapping = portMappings[i];
		if (portMapping.container_port < 0 || portMapping.container_port > 65535 || portMapping.host_port <= 0) {
			return false;
		}
	}
	return true;
}

