class Solution:
    def validate_port_mappings(self, port_mappings: list) -> bool:
        # Validate port mappings
        if not isinstance(port_mappings, list):
            return False
        for port_mapping in port_mappings:
            if port_mapping['container_port'] < 0 or port_mapping['container_port'] > 65535 or port_mapping['host_port'] <= 0:
                return False
        return True

# Read input from stdin
const readline = require('readline').createInterface({ input: process.stdin, output: process.stdout });
readline.question('Number of port mappings: ', n => {
    const n = parseInt(n);
    readline.question(`Port mappings (${n}): `, portMappings => {
        const solution = new Solution();
        const result = solution.validate_port_mappings(JSON.parse(portMappings));
        console.log(result ? 'true' : 'false');
        process.exit(0);
    });
});
